import{_ as a,c as i,o as t,ae as o}from"./chunks/framework.D4x4JNJ3.js";const g=JSON.parse('{"title":"Changelog v2025.1.x","description":"","frontmatter":{"title":"Changelog v2025.1.x"},"headers":[],"relativePath":"en/changelog/v2025.1.x.md","filePath":"en/changelog/v2025.1.x.md","lastUpdated":1772097359000}'),n={name:"en/changelog/v2025.1.x.md"};function s(r,e,l,d,c,m){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="mogan-stem-v2025-1-x-changelog" tabindex="-1">Mogan STEM v2025.1.x Changelog <a class="header-anchor" href="#mogan-stem-v2025-1-x-changelog" aria-label="Permalink to “Mogan STEM v2025.1.x Changelog”">​</a></h1><blockquote><p>Note: Liii STEM is the commercial edition of Mogan STEM. It provides value-added features on top of the open-source version, such as account login and AI. For details, see Liii STEM: <a href="https://liiistem.com/docs/changelog-v2025.1.x.html" target="_blank" rel="">v2025.1.x</a>.</p></blockquote><h2 id="⭐️-new-features-highlights" tabindex="-1">⭐️ New Features &amp; Highlights <a class="header-anchor" href="#⭐️-new-features-highlights" aria-label="Permalink to “⭐️ New Features &amp; Highlights”">​</a></h2><ol><li><strong>Modern UI, themes, and icons</strong>: Introduced Liii / Liii Dark themes and a full set of vector icons for a more consistent look.</li><li><strong>Core upgrade</strong>: Based on TeXmacs 2.1.4 and bundled with <strong>goldfish scheme</strong>.</li><li><strong>Tab Cycling &amp; smart completion</strong>: Completion for text, math, and macros; Tab cycling input for integrals/sums/products/sets and math alphabets (<code>\\mathcal</code>/<code>\\mathbf</code>/<code>\\mathfrak</code>, etc.).</li><li><strong>Better multi-tab workflow</strong>: New tab creation and switching shortcuts (macOS <code>Cmd+T</code>, <code>Cmd+1-6</code>), improved tab management and stability.</li><li><strong>Export and file handling</strong>: Better PDF export UX (progress + completion prompt); image type detection by file header to reduce export failures; improved format options in Save/Save As/Open dialogs.</li><li><strong>Stability &amp; performance</strong>: Faster startup/edit/render; fixed issues such as <code>&lt;</code>/<code>&gt;</code> ghosting, freezing when inserting Chinese ellipsis, copy crashes, and debug window failures.</li></ol><h2 id="🌟-summary" tabindex="-1">🌟 Summary <a class="header-anchor" href="#🌟-summary" aria-label="Permalink to “🌟 Summary”">​</a></h2><p>The v2025.1.x line focuses on a more modern interface, faster input, and a more reliable editing experience: themes/icons overhaul, Tab Cycling across text/math/macros and common symbols, improved multi-tab and export workflow, plus ongoing stability and performance improvements.</p><h2 id="🔧-release-notes" tabindex="-1">🔧 Release Notes <a class="header-anchor" href="#🔧-release-notes" aria-label="Permalink to “🔧 Release Notes”">​</a></h2><h3 id="mogan-stem-v2025-1-4-2025-10-06" tabindex="-1">Mogan STEM v2025.1.4 (2025/10/06) <a class="header-anchor" href="#mogan-stem-v2025-1-4-2025-10-06" aria-label="Permalink to “Mogan STEM v2025.1.4 (2025/10/06)”">​</a></h3><ol><li>Input enhancements: Tab cycling for integrals/sums/products/sets; improved Tab Cycling for math alphabets; added <code>\\mathscr</code> macro support.</li><li>PDF export: progress indicator and “open after export” prompt; image format detection by file header to avoid failures when extensions mismatch content.</li><li>Emoji: quick insertion via <code>:smile:</code>-style shortcuts.</li><li>UX and compatibility: show Meta as Win/Super on non-macOS; improved file format options in Save/Save As/Open; macOS compatibility fixes.</li><li>Fixes: freeze when inserting Chinese ellipsis, <code>&lt;</code>/<code>&gt;</code> ghosting, no line breaks in <code>verbatim</code>, crashes when copying large ranges, debug interactive window not opening, etc.</li></ol><h3 id="mogan-stem-v2025-1-1-2025-08-21" tabindex="-1">Mogan STEM v2025.1.1 (2025/08/21) <a class="header-anchor" href="#mogan-stem-v2025-1-1-2025-08-21" aria-label="Permalink to “Mogan STEM v2025.1.1 (2025/08/21)”">​</a></h3><ol><li>Renaming: Mogan was renamed to <strong>Mogan STEM</strong> and v2025.1.1 was released.</li><li>Core upgrade: based on TeXmacs 2.1.4 and bundled with <strong>goldfish scheme</strong>.</li><li>Themes and icons: introduced Liii / Liii Dark; refreshed and vectorized many icons; added toolbar entries such as highlighting (the built-in AI block entry is exclusive to Liii STEM; in Mogan it links to the Liii STEM website).</li><li>Tab completion: Tab Cycling in math; label/word completion; macro completion.</li><li>Multi-tabs: macOS <code>Cmd+T</code> to create a new tab, <code>Cmd+1-6</code> to switch tabs; added attach/detach window management and fixed many multi-tab issues.</li><li>Typesetting and editing: European numbering style for semantic blocks and new Assumption block; multiplication shows <code>×</code> by default with Tab alternatives; added LaTeX macros for multiple integrals; structured find/replace docked as an assistant window; Magic Paste improvements and Emoji (beta).</li><li>Performance: smoother startup, editing, and rendering.</li></ol><h2 id="👏-join-us" tabindex="-1">👏 Join Us <a class="header-anchor" href="#👏-join-us" aria-label="Permalink to “👏 Join Us”">​</a></h2><ul><li>Mogan STEM Official Website: <a href="https://mogan.app/" target="_blank" rel="">https://mogan.app/</a></li><li>Mogan Community QQ Group: <a href="https://qun.qq.com/universal-share/share?ac=1&amp;authKey=NoxIHFT4nzWfHJnqGNQygmXt%2FhpydluCE%2FcF1qMzu1BHpNNjv7ZGZxWwS0fGx32Y&amp;busi_data=eyJncm91cENvZGUiOiI5MzQ0NTY5NzEiLCJ0b2tlbiI6InpOMGxCaHIvdEtyM1V1d0VGYlpTQThZZ2NDODQxUjU1dWdBZEF5cG9MUHptN3R6Q1NXenNaWVluOVpjOTd3VHAiLCJ1aW4iOiI3ODUyNTEzMjIifQ%3D%3D&amp;data=n9XWNwOuQOWPbezHFAHZS24nvSli9BNzrLjrfFr_JWfStSboc6G5DZwBXWzZDqXc5A29OptCvKgtVjZ1Gwmu1A&amp;svctype=4&amp;tempid=h5_group_info" target="_blank" rel="">934456971</a></li><li>Discord Group: <a href="https://discord.gg/Q7xARnAf8t" target="_blank" rel="">https://discord.gg/Q7xARnAf8t</a></li></ul>',13)])])}const p=a(n,[["render",s]]);export{g as __pageData,p as default};
